```ts
// IMPORTANT: leave this on the Node.js runtime (not "edge").
// Fluid Compute applies to Node.js / Python functions and is what
// gives you real chunked streaming + concurrency on that runtime.
export const config = {
  runtime: 'nodejs',
};

import { Hono } from 'hono';
import { handle } from 'hono/vercel';
import { streamSSE } from 'hono/streaming';

const app = new Hono().basePath('/api');

app.get('/health', (c) => c.json({ ok: true }));

// A finite demo stream: 10 ticks, one per second.
app.get('/sse', (c) => {
  return streamSSE(c, async (stream) => {
    let aborted = false;
    stream.onAbort(() => {
      aborted = true;
      console.log('client disconnected, stopping stream');
    });

    for (let i = 0; i < 10 && !aborted; i++) {
      await stream.writeSSE({
        event: 'tick',
        id: String(i),
        data: JSON.stringify({ i, ts: Date.now() }),
      });
      await stream.sleep(1000);
    }

    await stream.writeSSE({ event: 'done', data: 'stream complete' });
  });
});

// A long-lived stream that relies on Fluid Compute's longer maxDuration
// and non-buffered writes. Client (or the abort signal) ends it.
app.get('/sse/forever', (c) => {
  return streamSSE(c, async (stream) => {
    let n = 0;
    let aborted = false;
    stream.onAbort(() => (aborted = true));

    while (!aborted) {
      await stream.writeSSE({
        event: 'heartbeat',
        id: String(n++),
        data: new Date().toISOString(),
      });
      await stream.sleep(2000);
    }
  });
});

export default handle(app);
```

Notes on `streamSSE`:
- It returns a `Response` wrapping a `ReadableStream` immediately — the handler function you pass runs concurrently, writing chunks as they're ready. Hono sets `Content-Type: text/event-stream`, `Cache-Control: no-cache`, `Connection: keep-alive`, and chunked transfer for you.
- Always wire `stream.onAbort()` — if the client disconnects and you don't check it, your loop keeps running (and billing) until `maxDuration` hits.

