### `source/src/client.ts`

```typescript
import type { CFResponse, GatewayConfig, GatewayResult } from "./types.js";
import type { Env } from "./env.js";

export class CFApiError extends Error {
  constructor(
    public status: number,
    public errors: { code: number; message: string }[],
    public endpoint: string
  ) {
    super(
      `Cloudflare API error at ${endpoint}: HTTP ${status} — ` +
        errors.map((e) => `[${e.code}] ${e.message}`).join("; ")
    );
    this.name = "CFApiError";
  }
}

/**
 * Thin client for the AI Gateway management API.
 * Real HTTP calls only -- no mocking. Requires env.apiToken to be a
 * CF API Token scoped with "Cloudflare AI Gateway: Edit" (account level).
 */
export class AIGatewayClient {
  constructor(private env: Env) {}

  private endpoint(path = ""): string {
    return `${this.env.baseUrl}/accounts/${this.env.accountId}/ai-gateway/gateways${path}`;
  }

  private async request<T>(
    method: string,
    path: string,
    body?: unknown
  ): Promise<{ status: number; json: CFResponse<T> }> {
    if (!this.env.apiToken) {
      throw new Error(
        "CF_API_TOKEN is not set. This client requires a CF API Token " +
          '(Account -> "Cloudflare AI Gateway: Edit"), not a wrangler OAuth token.'
      );
    }

    const url = this.endpoint(path);
    const res = await fetch(url, {
      method,
      headers: {
        Authorization: `Bearer ${this.env.apiToken}`,
        "Content-Type": "application/json",
      },
      body: body ? JSON.stringify(body) : undefined,
    });

    const json = (await res.json()) as CFResponse<T>;
    return { status: res.status, json };
  }

  async listGateways(): Promise<{ status: number; json: CFResponse<GatewayResult[]> }> {
    return this.request<GatewayResult[]>("GET", "");
  }

  async getGateway(
    id: string
  ): Promise<{ status: number; json: CFResponse<GatewayResult> }> {
    return this.request<GatewayResult>("GET", `/${id}`);
  }

  async createGateway(
    config: GatewayConfig
  ): Promise<{ status: number; json: CFResponse<GatewayResult> }> {
    return this.request<GatewayResult>("POST", "", config);
  }

  async deleteGateway(
    id: string
  ): Promise<{ status: number; json: CFResponse<unknown> }> {
    return this.request<unknown>("DELETE", `/${id}`);
  }

  /** Raw fetch used only to reproduce/document the 403 auth-scope blocker. */
  async rawAuthProbe(token: string): Promise<{ status: number; body: unknown }> {
    const res = await fetch(this.endpoint(), {
      method: "GET",
      headers: { Authorization: `Bearer ${token}` },
    });
    return { status: res.status, body: await res.json() };
  }
}

export const DEFAULT_GATEWAY_CONFIG = (id: string): GatewayConfig => ({
  id,
  cache_invalidate_on_update: false,
  cache_ttl: 0,
  collect_logs: true,
  rate_limiting_interval: 0,
  rate_limiting_limit: 0,
  rate_limiting_technique: "fixed",
});
```

### `source/src/create-gateway.ts`

```typescript
import { loadEnv, GATEWAY_ID } from "./env.js";
import { AIGatewayClient, DEFAULT_GATEWAY_CONFIG, CFApiError } from "./client.js";

/**
 * Idempotent creation script:
 *  1. GET the gateway — if it already exists, print it and exit 0.
 *  2. Otherwise POST to create it.
 *  3. GET again to confirm, and list all gateways for visibility.
 *
 * Run: npm run create-gateway   (requires CF_API_TOKEN with
 * "Cloudflare AI Gateway: Edit" set in the environment or .env)
 */
async function main() {
  const env = loadEnv();

  if (!env.apiToken) {
    console.error(
      "BLOCKED: CF_API_TOKEN is not set.\n" +
        "The wrangler OAuth token does NOT have the required scope " +
        '("Cloudflare AI Gateway: Edit") and will be rejected with HTTP 403.\n' +
        "Create a scoped token at https://dash.cloudflare.com/profile/api-tokens " +
        "and export CF_API_TOKEN before retrying."
    );
    process.exit(1);
  }

  const client = new AIGatewayClient(env);

  const existing = await client.getGateway(GATEWAY_ID);
  if (existing.status === 200 && existing.json.success) {
    console.log(`Gateway "${GATEWAY_ID}" already exists:`);
    console.log(JSON.stringify(existing.json.result, null, 2));
    return;
  }

  console.log(`Creating gateway "${GATEWAY_ID}"...`);
  const config = DEFAULT_GATEWAY_CONFIG(GATEWAY_ID);
  const created = await client.createGateway(config);

  if (!created.json.success || created.status !== 200) {
    throw new CFApiError(
      created.status,
      created.json.errors,
      "/ai-gateway/gateways (POST)"
    );
  }

  console.log("Created:", JSON.stringify(created.json.result, null, 2));

  const confirm = await client.getGateway(GATEWAY_ID);
  console.log(
    "Confirmed via GET:",
    JSON.stringify(confirm.json.result, null, 2)
  );

  const list = await client.listGateways();
  const ids = (list.json.result ?? []).map((g) => g.id);
  console.log("All gateways on account:", ids);
}

main().catch((err) => {
  console.error(err instanceof Error ? err.message : err);
  process.exit(1);
});
```

