/**
 * Every scenario in this file funnels through these two recorders so the
 * captured shape is uniform and directly transcribable into evidence.md:
 * scenario name, whether it threw, error class name, code, HTTP status
 * (wherever the SDK attaches one), and message. Nothing here mocks a
 * response — every recorder call wraps a real awaited SDK call.
 */
interface CapturedFailure {
  scenario: string;
  threw: boolean;
  errorClass?: string;
  code?: string;
  status?: number;
  message?: string;
  raw?: unknown;
}

const captured: CapturedFailure[] = [];

function recordThrow(scenario: string, err: unknown): CapturedFailure {
  const anyErr = err as any;
  const rec: CapturedFailure = {
    scenario,
    threw: true,
    errorClass: anyErr?.constructor?.name,
    code: anyErr?.code,
    status: anyErr?.status ?? anyErr?.statusCode ?? anyErr?.response?.status,
    message: anyErr?.message,
  };
  captured.push(rec);
  // eslint-disable-next-line no-console
  console.log(`[L5][${scenario}] THREW`, JSON.stringify(rec, null, 2));
  return rec;
}

function recordResult(scenario: string, result: unknown): CapturedFailure {
  const rec: CapturedFailure = { scenario, threw: false, raw: result };
  captured.push(rec);
  console.log(`[L5][${scenario}] returned (no throw)`, JSON.stringify(result, null, 2));
  return rec;
}

