// The adapter seam. Any remote runtime (E2B, Daytona, Modal, or Smithers
// itself once its client is available) implements this contract.

export interface SandboxHandle {
  id: string;
  providerName: string;
}

export interface CommandResult {
  stdout: string;
  stderr: string;
  exitCode: number;
}

export interface SandboxProvider {
  readonly name: string;

  /** Provision a real remote sandbox. Must hit the network — no stubs. */
  createSandbox(opts?: { timeoutMs?: number }): Promise<SandboxHandle>;

  /** Execute a command inside the remote sandbox and wait for completion. */
  runCommand(handle: SandboxHandle, command: string): Promise<CommandResult>;

  /** Tear down the remote resource. Must be called or you leak billable sandboxes. */
  destroySandbox(handle: SandboxHandle): Promise<void>;
}
```

