### `src/sandbox/providers/E2BSandboxProvider.ts`

```typescript
import { Sandbox } from "e2b"; // npm i e2b  — pin version, API shape changed 0.x -> 1.x
import type { SandboxProvider, SandboxHandle, CommandResult } from "../SandboxProvider";

/**
 * Real remote runtime adapter. Every call here is a network round trip to
 * E2B's control plane; there is no local fallback path in this class.
 *
 * Requires E2B_API_KEY in the environment (https://e2b.dev/dashboard).
 */
export class E2BSandboxProvider implements SandboxProvider {
  readonly name = "e2b";
  private live = new Map<string, Sandbox>();

  async createSandbox(opts?: { timeoutMs?: number }): Promise<SandboxHandle> {
    if (!process.env.E2B_API_KEY) {
      throw new Error(
        "E2B_API_KEY not set — refusing to fake a sandbox. Set the env var to run for real."
      );
    }

    const sandbox = await Sandbox.create({
      apiKey: process.env.E2B_API_KEY,
      timeoutMs: opts?.timeoutMs ?? 60_000,
    });

    this.live.set(sandbox.sandboxId, sandbox);
    return { id: sandbox.sandboxId, providerName: this.name };
  }

  async runCommand(handle: SandboxHandle, command: string): Promise<CommandResult> {
    const sandbox = this.live.get(handle.id);
    if (!sandbox) {
      throw new Error(`No live sandbox tracked for id ${handle.id}`);
    }

    const result = await sandbox.commands.run(command);
    return {
      stdout: result.stdout,
      stderr: result.stderr,
      exitCode: result.exitCode,
    };
  }

  async destroySandbox(handle: SandboxHandle): Promise<void> {
    const sandbox = this.live.get(handle.id);
    if (!sandbox) return;
    await sandbox.kill();
    this.live.delete(handle.id);
  }
}
```

**Pitfall flag:** E2B's SDK renamed its execution surface between major versions (`process.startAndWait()` in older 0.x releases vs. `commands.run()` in current 1.x). If `npm i e2b` resolves to an older major, this code will throw a type error at compile time, not silently fake success — check `node_modules/e2b/package.json` version and the docs at install time rather than trusting this snippet blindly.

