### `src/sandbox/providers/index.ts`

```typescript
import type { SandboxProvider } from "../SandboxProvider";
import { E2BSandboxProvider } from "./E2BSandboxProvider";

const registry: Record<string, () => SandboxProvider> = {
  e2b: () => new E2BSandboxProvider(),
  // daytona: () => new DaytonaSandboxProvider(),   // not implemented — no live creds tested
  // smithers: () => new SmithersSandboxProvider(), // drop-in seam once client + creds exist
};

export function getSandboxProvider(name = process.env.SANDBOX_PROVIDER ?? "e2b"): SandboxProvider {
  const factory = registry[name];
  if (!factory) {
    throw new Error(`Unknown or unimplemented SandboxProvider: ${name}`);
  }
  return factory();
}
