### `src/db/runLedger.ts`

```typescript
import { Pool } from "pg"; // npm i pg

const pool = new Pool({ connectionString: process.env.DATABASE_URL });

export async function insertRunStarted(provider: string, sandboxId: string, command: string) {
  const { rows } = await pool.query(
    `INSERT INTO sandbox_runs (provider, sandbox_id, command, status)
     VALUES ($1, $2, $3, 'running')
     RETURNING id`,
    [provider, sandboxId, command]
  );
  return rows[0].id as number;
}

export async function updateRunResult(
  rowId: number,
  status: "succeeded" | "failed",
  stdout: string,
  stderr: string,
  exitCode: number | null
) {
  await pool.query(
    `UPDATE sandbox_runs
     SET status = $2, stdout = $3, stderr = $4, exit_code = $5, finished_at = now()
     WHERE id = $1`,
    [rowId, status, stdout, stderr, exitCode]
  );
}

export async function closePool() {
  await pool.end();
}
```

Writing the "running" row **before** the remote call, then updating it after, is deliberate: if the process crashes mid-run, you're left with a real, auditable stuck row instead of silence — that's the actual operational seam this POC level is testing for.

