### `src/cli/runSandboxTask.ts`

```typescript
import { getSandboxProvider } from "../sandbox/providers";
import { insertRunStarted, updateRunResult, closePool } from "../db/runLedger";

async function main() {
  const command = process.argv.slice(2).join(" ") || "echo hello-from-remote-sandbox";
  const provider = getSandboxProvider();

  const handle = await provider.createSandbox();
  const rowId = await insertRunStarted(provider.name, handle.id, command);

  try {
    const result = await provider.runCommand(handle, command);
    await updateRunResult(
      rowId,
      result.exitCode === 0 ? "succeeded" : "failed",
      result.stdout,
      result.stderr,
      result.exitCode
    );
    console.log(JSON.stringify({ rowId, ...result }, null, 2));
  } catch (err) {
    await updateRunResult(rowId, "failed", "", String(err), null);
    throw err;
  } finally {
    await provider.destroySandbox(handle);
    await closePool();
  }
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
```

