### `test/e2b-live.spec.ts`

```typescript
import { describe, it, expect } from "vitest";
import { E2BSandboxProvider } from "../src/sandbox/providers/E2BSandboxProvider";

// Intentionally SKIPPED, not faked, when there's no live key.
// A green run of this test with no key is a red flag — it means
// something got mocked. A skip is the honest signal instead.
const hasLiveKey = !!process.env.E2B_API_KEY;

describe.skipIf(!hasLiveKey)("E2BSandboxProvider — live remote execution", () => {
  it("actually runs a command in a real remote sandbox", async () => {
    const provider = new E2BSandboxProvider();
    const handle = await provider.createSandbox();
    const result = await provider.runCommand(handle, "echo hi-from-e2b");
    await provider.destroySandbox(handle);

    expect(result.stdout.trim()).toBe("hi-from-e2b");
    expect(result.exitCode).toBe(0);
  });
});
